    <textarea class="message-textarea"
              placeholder="@Placeholder"
              @bind="messageText"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              rows="2"></textarea>
    <button class="send-button" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(messageText)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string messageText = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(messageText))
            return;

        var text = messageText.Trim();
        messageText = string.Empty;
        await OnSubmit.InvokeAsync(text);
    }
}
"}

