@using sv_3aeb1d6e47174fb593e201fdaf9c2143.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnChannelSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background-color: #1e1e2e;
    border-right: 1px solid #333;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #333;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 6px 0;
}

@using sv_3aeb1d6e47174fb593e201fdaf9c2143.Services
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list-container">
    @if (HasMore)
    {
        <div class="load-more-area">
            <button class="load-more-btn" @onclick="LoadMore" disabled="@isLoadingMore">
                @(isLoadingMore ? "Loading…" : "Load older messages")
            </button>
        </div>
    }

    <div class="message-list" id="@scrollContainerId" @ref="scrollContainer">
        @foreach (var message in Messages)
        {
            <MessageBubble Message="message"
                           ReplyCount="GetReplyCount(message.Id)"
                           OnReplyClicked="OnReplyClicked"
                           OnThreadClicked="OnThreadClicked"
                           OnReactionAdded="OnReactionAdded" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<int> OnThreadClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private ElementReference scrollContainer;
    private IJSObjectReference? jsModule;
    private bool isLoadingMore;
    private string scrollContainerId = $"msg-list-{Guid.NewGuid():N}";
    private int previousMessageCount;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-3aeb1d6e47174fb593e201fdaf9c2143/Components/Chat/MessageList.razor.js");
            await jsModule.InvokeVoidAsync("scrollToBottom", scrollContainerId);
            previousMessageCount = Messages.Count;
        }
        else if (Messages.Count != previousMessageCount)
        {
            if (!isLoadingMore)
            {
                // New messages added at the bottom — scroll down
                await jsModule!.InvokeVoidAsync("scrollToBottom", scrollContainerId);
            }
            previousMessageCount = Messages.Count;
        }
    }

    private async Task LoadMore()
    {
        isLoadingMore = true;
        await OnLoadMore.InvokeAsync();
        isLoadingMore = false;
    }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId, 0);

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            await jsModule.DisposeAsync();
        }
    }
}

.message-list-container {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

.load-more-area {
    text-align: center;
    padding: 8px;
    flex-shrink: 0;
}

.load-more-btn {
    padding: 4px 16px;
    border: 1px solid #444;
    border-radius: 6px;
    background-color: #333;
    color: #bbb;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.load-more-btn:hover:not(:disabled) {
    background-color: #444;
    color: #fff;
}

.load-more-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

export function scrollToBottom(elementId) {
    const el = document.getElementById(elementId);
    if (el) {
        el.scrollTop = el.scrollHeight;
    }
}

@using sv_3aeb1d6e47174fb593e201fdaf9c2143.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="root-author">@RootMessage.Author</span>
            <p class="root-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnReplySent" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReplySent { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 30) return "just now";
        if (diff.TotalMinutes < 1) return $"{(int)diff.TotalSeconds}s ago";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

