+@using sv_3aeb1d6e47174fb593e201fdaf9c2143.Services
+@inject IJSRuntime JS
+@implements IAsyncDisposable
+
+<div class="message-list-container">
+    @if (HasMore)
+    {
+        <div class="load-more-area">
+            <button class="load-more-btn" @onclick="LoadMore" disabled="@isLoadingMore">
+                @(isLoadingMore ? "Loading…" : "Load older messages")
+            </button>
+        </div>
+    }
+
+    <div class="message-list" id="@scrollContainerId" @ref="scrollContainer">
+        @foreach (var message in Messages)
+        {
+            <MessageBubble Message="message"
+                           ReplyCount="GetReplyCount(message.Id)"
+                           OnReplyClicked="OnReplyClicked"
+                           OnThreadClicked="OnThreadClicked"
+                           OnReactionAdded="OnReactionAdded" />
+        }
+    </div>
+</div>
+
+@code {
+    [Parameter] public List<Message> Messages { get; set; } = [];
+    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
+    [Parameter] public bool HasMore { get; set; }
+    [Parameter] public EventCallback OnLoadMore { get; set; }
+    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
+    [Parameter] public EventCallback<int> OnThreadClicked { get; set; }
+    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
+
+    private ElementReference scrollContainer;
+    private IJSObjectReference? jsModule;
+    private bool isLoadingMore;
+    private string scrollContainerId = $"msg-list-{Guid.NewGuid():N}";
+    private int previousMessageCount;
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            jsModule = await JS.InvokeAsync<IJSObjectReference>(
+                "import", "./_content/sv-3aeb1d6e47174fb593e201fdaf9c2143/Components/Chat/MessageList.razor.js");
+            await jsModule.InvokeVoidAsync("scrollToBottom", scrollContainerId);
+            previousMessageCount = Messages.Count;
+        }
+        else if (Messages.Count != previousMessageCount)
+        {
+            if (!isLoadingMore)
+            {
+                // New messages added at the bottom — scroll down
+                await jsModule!.InvokeVoidAsync("scrollToBottom", scrollContainerId);
+            }
+            previousMessageCount = Messages.Count;
+        }
+    }
+
+    private async Task LoadMore()
+    {
+        isLoadingMore = true;
+        await OnLoadMore.InvokeAsync();
+        isLoadingMore = false;
+    }
+
+    private int GetReplyCount(int messageId) =>
+        ThreadReplyCounts.GetValueOrDefault(messageId, 0);
+
+    public async ValueTask DisposeAsync()
+    {
+        if (jsModule is not null)
+        {
+            await jsModule.DisposeAsync();
+        }
+    }
+}
