    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #333;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    padding: 4px 8px;
    border: none;
    background: none;
    color: #999;
    font-size: 1.1rem;
    cursor: pointer;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background-color: rgba(255, 255, 255, 0.1);
    color: #fff;
}

.thread-root-message {
    padding: 12px 16px;
