    background-color: rgba(255, 255, 255, 0.03);
}

.root-author {
    font-weight: 700;
    font-size: 0.88rem;
    color: #e0e0e0;
}

.root-content {
    margin: 4px 0 0;
    font-size: 0.88rem;
    color: #bbb;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    padding: 6px 16px;
    text-align: center;
