@page "/chat"
@rendermode InteractiveServer
@using sv_3aeb1d6e47174fb593e201fdaf9c2143.Services
@using sv_3aeb1d6e47174fb593e201fdaf9c2143.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(threadOpen ? "with-thread" : "")">
        @if (selectedChannel is not null)
        {
            <div class="channel-header">
                <h2># @selectedChannel.Name</h2>
                <span class="channel-desc">@selectedChannel.Description</span>
            </div>

            <MessageList Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         HasMore="hasMoreMessages"
                         OnLoadMore="LoadOlderMessages"
                         OnReplyClicked="OpenThread"
                         OnThreadClicked="OpenThread"
                         OnReactionAdded="AddReaction" />

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
                          OnSubmit="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnReplySent="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Channel? selectedChannel;
    private int selectedChannelId;
    private int loadedCount;
    private bool hasMoreMessages;

    // Thread state
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    // Computed from loaded messages: messageId → reply count
    private Dictionary<int, int> threadReplyCounts = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        loadedCount = 0;
        messages = [];
        threadReplyCounts = [];
        CloseThreadSync();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        loadedCount = loaded.Count;
        hasMoreMessages = loaded.Count == PageSize;
        ComputeThreadReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);
        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadOlderMessages()
    {
        if (selectedChannel is null) return;

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, loadedCount, PageSize);
        messages.InsertRange(0, older);
        loadedCount += older.Count;
        hasMoreMessages = older.Count == PageSize;
        ComputeThreadReplyCounts();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;

        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadMessages = await ChatService.GetThreadAsync(messageId);
        threadOpen = true;
    }

    private void CloseThreadSync()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private Task CloseThread()
    {
        CloseThreadSync();
        return Task.CompletedTask;
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || selectedChannel is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update reply count in the main message list
        threadReplyCounts[threadRootMessage.Id] = threadMessages.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        if (selectedChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, loadedCount);
            messages = refreshed;
        }
    }

    private void ComputeThreadReplyCounts()
    {
        threadReplyCounts = messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}

.chat-layout {
    display: flex;
    height: calc(100vh - 66px);
    background-color: #1a1a2e;
    color: #e0e0e0;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    background-color: #2b2b3b;
    overflow: hidden;
    min-width: 0;
}

.chat-main.with-thread {
    flex: 0 0 55%;
}

.chat-thread {
    width: 25%;
    min-width: 260px;
    max-width: 380px;
    flex-shrink: 0;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #3a3a3a;
    flex-shrink: 0;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-desc {
    font-size: 0.82rem;
    color: #999;
    margin-top: 2px;
    display: block;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #777;
    font-size: 1.1rem;
}

