+                <h2># @selectedChannel.Name</h2>
+                <span class="channel-desc">@selectedChannel.Description</span>
+            </div>
+
+            <MessageList Messages="messages"
+                         ThreadReplyCounts="threadReplyCounts"
+                         HasMore="hasMoreMessages"
+                         OnLoadMore="LoadOlderMessages"
+                         OnReplyClicked="OpenThread"
+                         OnThreadClicked="OpenThread"
+                         OnReactionAdded="AddReaction" />
+
+            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
+                          OnSubmit="SendMessage" />
+        }
+        else
+        {
+            <div class="no-channel-selected">
+                <p>Select a channel to start chatting</p>
+            </div>
+        }
+    </div>
+
+    @if (threadOpen)
+    {
+        <div class="chat-thread">
+            <ThreadPanel RootMessage="threadRootMessage"
+                         ThreadMessages="threadMessages"
+                         OnClose="CloseThread"
+                         OnReplySent="SendThreadReply" />
+        </div>
+    }
