+@code {
+    private const int PageSize = 30;
+
+    private List<Channel> channels = [];
+    private List<Message> messages = [];
+    private Channel? selectedChannel;
+    private int selectedChannelId;
+    private int loadedCount;
+    private bool hasMoreMessages;
+
+    // Thread state
+    private bool threadOpen;
+    private Message? threadRootMessage;
+    private List<Message> threadMessages = [];
+
+    // Computed from loaded messages: messageId → reply count
+    private Dictionary<int, int> threadReplyCounts = [];
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+        if (channels.Count > 0)
+        {
+            await SelectChannel(channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        selectedChannelId = channelId;
+        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
+        loadedCount = 0;
+        messages = [];
+        threadReplyCounts = [];
+        CloseThreadSync();
+
+        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        messages = loaded;
+        loadedCount = loaded.Count;
+        hasMoreMessages = loaded.Count == PageSize;
+        ComputeThreadReplyCounts();
+
+        await ChatService.MarkChannelReadAsync(channelId);
+        // Refresh channel list to update unread counts
+        channels = await ChatService.GetChannelsAsync();
+    }
+
+    private async Task LoadOlderMessages()
+    {
+        if (selectedChannel is null) return;
+
+        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, loadedCount, PageSize);
+        messages.InsertRange(0, older);
+        loadedCount += older.Count;
+        hasMoreMessages = older.Count == PageSize;
+        ComputeThreadReplyCounts();
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (selectedChannel is null) return;
+
+        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
+        messages.Add(newMessage);
+    }
+
+    private async Task OpenThread(int messageId)
+    {
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
+        if (threadRootMessage is null) return;
+
+        threadMessages = await ChatService.GetThreadAsync(messageId);
+        threadOpen = true;
+    }
+
+    private void CloseThreadSync()
+    {
+        threadOpen = false;
+        threadRootMessage = null;
+        threadMessages = [];
+    }
+
+    private Task CloseThread()
+    {
+        CloseThreadSync();
+        return Task.CompletedTask;
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (threadRootMessage is null || selectedChannel is null) return;
+
+        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
+        threadMessages.Add(reply);
+
+        // Update reply count in the main message list
+        threadReplyCounts[threadRootMessage.Id] = threadMessages.Count;
+    }
+
+    private async Task AddReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Refresh messages to show updated reactions
+        if (selectedChannel is not null)
+        {
+            var refreshed = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, loadedCount);
+            messages = refreshed;
+        }
+    }
+
+    private void ComputeThreadReplyCounts()
+    {
+        threadReplyCounts = messages
+            .Where(m => m.ReplyToId.HasValue)
+            .GroupBy(m => m.ReplyToId!.Value)
+            .ToDictionary(g => g.Key, g => g.Count());
+    }
+}
+

