toolArgs.file_text:
.chat-layout {
    display: flex;
    height: calc(100vh - 66px);
    background-color: #1a1a2e;
    color: #e0e0e0;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    background-color: #2b2b3b;
    overflow: hidden;
    min-width: 0;
}

.chat-main.with-thread {
    flex: 0 0 55%;
}

.chat-thread {
    width: 25%;
    min-width: 260px;
    max-width: 380px;
    flex-shrink: 0;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #3a3a3a;
    flex-shrink: 0;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-desc {
    font-size: 0.82rem;
    color: #999;
    margin-top: 2px;
    display: block;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #777;
    font-size: 1.1rem;
}

